// ================================
// CHARTS PAGE
// ================================

import React, { useState, useEffect } from 'react';
import { BarChart3, TrendingUp, TrendingDown, Search, Clock } from 'lucide-react';
import { useTrading } from '../contexts/TradingContext';

export default function ChartsPage() {
  const { markets, fetchMarkets } = useTrading();
  const [selectedCrypto, setSelectedCrypto] = useState('BTC');
  const [timeFrame, setTimeFrame] = useState('1D');
  const [searchQuery, setSearchQuery] = useState('');
  const [chartType, setChartType] = useState('candle');

  useEffect(() => {
    fetchMarkets();
  }, []);

  const selectedCoin = markets.find(m => m.symbol === selectedCrypto) || markets[0];
  const filteredMarkets = markets.filter(m =>
    m.symbol.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Generate mock chart data
  const generateChartData = (symbol, days = 30) => {
    const data = [];
    const basePrice = Math.random() * 50000 + 20000;
    
    for (let i = 0; i < days; i++) {
      const date = new Date();
      date.setDate(date.getDate() - days + i);
      
      const variation = (Math.random() - 0.5) * 5000;
      const open = basePrice + variation;
      const close = open + (Math.random() - 0.5) * 2000;
      const high = Math.max(open, close) + Math.random() * 1000;
      const low = Math.min(open, close) - Math.random() * 1000;
      
      data.push({
        date: date.toLocaleDateString(),
        open: open.toFixed(2),
        close: close.toFixed(2),
        high: high.toFixed(2),
        low: low.toFixed(2),
        volume: Math.random() * 10000000
      });
    }
    return data;
  };

  const chartData = generateChartData(selectedCrypto);
  const cryptoList = markets.slice(0, 10);

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h1 className="text-4xl font-bold text-white flex items-center gap-2">
          <BarChart3 size={32} className="text-cyan-400" />
          Charts & Analytics
        </h1>
      </div>

      {/* Main Chart Section */}
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Chart Area */}
        <div className="lg:col-span-3 space-y-4">
          {/* Chart Header */}
          <div className="bg-gradient-to-r from-slate-800/50 to-slate-900/50 border border-slate-700/50 rounded-xl p-6">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h2 className="text-2xl font-bold text-white">{selectedCrypto}/USD</h2>
                <p className="text-sm text-slate-400 mt-1">
                  {selectedCoin?.name || 'Cryptocurrency'}
                </p>
              </div>
              <div className="text-right">
                <p className="text-3xl font-bold text-white">
                  ${selectedCoin?.currentPrice?.toFixed(2) || 'N/A'}
                </p>
                <div className={`text-lg font-semibold flex items-center justify-end gap-1 ${
                  selectedCoin?.percentChange >= 0
                    ? 'text-green-400'
                    : 'text-red-400'
                }`}>
                  {selectedCoin?.percentChange >= 0 ? (
                    <TrendingUp size={20} />
                  ) : (
                    <TrendingDown size={20} />
                  )}
                  {selectedCoin?.percentChange?.toFixed(2)}%
                </div>
              </div>
            </div>

            {/* Timeframe Selector */}
            <div className="flex gap-2">
              {['1H', '4H', '1D', '1W', '1M'].map(tf => (
                <button
                  key={tf}
                  onClick={() => setTimeFrame(tf)}
                  className={`px-4 py-2 rounded-lg font-semibold transition ${
                    timeFrame === tf
                      ? 'bg-cyan-600 text-white'
                      : 'bg-slate-700/50 text-slate-300 hover:bg-slate-600/50'
                  }`}
                >
                  {tf}
                </button>
              ))}
            </div>
          </div>

          {/* Chart Visualization */}
          <div className="bg-gradient-to-br from-slate-800/50 to-slate-900/50 border border-slate-700/50 rounded-xl p-6 h-96">
            {/* Simple Chart Representation */}
            <div className="w-full h-full flex flex-col items-center justify-center space-y-4">
              <div className="text-center">
                <h3 className="text-lg font-semibold text-white mb-2">Live Chart</h3>
                <p className="text-slate-400 text-sm">
                  {selectedCrypto} Price Chart - {timeFrame}
                </p>
              </div>

              {/* Bar Chart Representation */}
              <div className="w-full h-48 flex items-end justify-center gap-1">
                {chartData.slice(-20).map((point, idx) => {
                  const close = parseFloat(point.close);
                  const open = parseFloat(point.open);
                  const isUp = close >= open;
                  const minPrice = Math.min(...chartData.map(p => parseFloat(p.low)));
                  const maxPrice = Math.max(...chartData.map(p => parseFloat(p.high)));
                  const range = maxPrice - minPrice;
                  const normalizedHigh = ((parseFloat(point.high) - minPrice) / range) * 100;

                  return (
                    <div
                      key={idx}
                      className={`flex-1 rounded-t transition hover:opacity-80 ${
                        isUp ? 'bg-green-500/60' : 'bg-red-500/60'
                      }`}
                      style={{
                        height: `${Math.max(10, normalizedHigh)}%`,
                        minHeight: '10px'
                      }}
                      title={`${point.date}: $${point.close}`}
                    />
                  );
                })}
              </div>

              <p className="text-xs text-slate-400">Interactive chart data - 20 most recent periods</p>
            </div>
          </div>

          {/* Chart Type Selector */}
          <div className="bg-gradient-to-r from-slate-800/50 to-slate-900/50 border border-slate-700/50 rounded-xl p-4 flex gap-2">
            {['candle', 'line', 'bar'].map(type => (
              <button
                key={type}
                onClick={() => setChartType(type)}
                className={`px-4 py-2 rounded-lg font-semibold capitalize transition ${
                  chartType === type
                    ? 'bg-cyan-600 text-white'
                    : 'bg-slate-700/50 text-slate-300 hover:bg-slate-600/50'
                }`}
              >
                {type} Chart
              </button>
            ))}
          </div>
        </div>

        {/* Sidebar - Crypto List */}
        <div className="lg:col-span-1 space-y-4">
          {/* Search */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input
              type="text"
              placeholder="Search coins..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-slate-900/50 border border-slate-700/50 rounded-lg text-white text-sm focus:border-cyan-500/50 focus:outline-none"
            />
          </div>

          {/* Crypto List */}
          <div className="bg-gradient-to-br from-slate-800/50 to-slate-900/50 border border-slate-700/50 rounded-xl overflow-hidden">
            <div className="max-h-96 overflow-y-auto">
              {(searchQuery ? filteredMarkets : cryptoList).map((coin) => (
                <button
                  key={coin.symbol}
                  onClick={() => {
                    setSelectedCrypto(coin.symbol);
                    setSearchQuery('');
                  }}
                  className={`w-full px-4 py-3 text-left border-b border-slate-700/30 hover:bg-slate-800/50 transition ${
                    selectedCrypto === coin.symbol
                      ? 'bg-cyan-600/20 border-l-2 border-l-cyan-500'
                      : ''
                  }`}
                >
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="font-semibold text-white text-sm">{coin.symbol}</p>
                      <p className="text-xs text-slate-400">${coin.currentPrice?.toFixed(2) || 'N/A'}</p>
                    </div>
                    <div className={`text-xs font-bold ${
                      coin.percentChange >= 0 ? 'text-green-400' : 'text-red-400'
                    }`}>
                      {coin.percentChange?.toFixed(1)}%
                    </div>
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Forex Section */}
      <div className="space-y-4">
        <h2 className="text-2xl font-bold text-white">Forex Pairs</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {[
            { pair: 'EUR/USD', price: '1.0950', change: 0.45 },
            { pair: 'GBP/USD', price: '1.2680', change: -0.32 },
            { pair: 'USD/JPY', price: '149.30', change: 0.78 },
            { pair: 'AUD/USD', price: '0.6550', change: -0.12 },
            { pair: 'USD/CAD', price: '1.3620', change: 0.25 },
            { pair: 'USD/CHF', price: '0.8810', change: -0.18 },
          ].map((forex) => (
            <div
              key={forex.pair}
              className="bg-gradient-to-br from-slate-800/50 to-slate-900/50 border border-slate-700/50 hover:border-cyan-500/50 rounded-xl p-4 transition cursor-pointer"
            >
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-bold text-white">{forex.pair}</h3>
                <span className={`text-sm font-semibold px-2 py-1 rounded ${
                  forex.change >= 0
                    ? 'bg-green-500/20 text-green-400'
                    : 'bg-red-500/20 text-red-400'
                }`}>
                  {forex.change > 0 ? '+' : ''}{forex.change}%
                </span>
              </div>
              <p className="text-2xl font-bold text-cyan-400">{forex.price}</p>
              <button className="w-full mt-3 px-4 py-2 bg-cyan-600/20 text-cyan-400 border border-cyan-500/50 rounded-lg hover:bg-cyan-600/40 transition text-sm font-semibold">
                Trade
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {[
          { label: 'Total Market Cap', value: '$2.1T', change: '+2.5%' },
          { label: '24h Volume', value: '$89.3B', change: '+4.2%' },
          { label: 'BTC Dominance', value: '42.5%', change: '+0.8%' },
          { label: 'Fear & Greed', value: '65 (Greed)', change: '+3.2%' },
        ].map((stat) => (
          <div
            key={stat.label}
            className="bg-gradient-to-br from-slate-800/50 to-slate-900/50 border border-slate-700/50 rounded-xl p-4"
          >
            <p className="text-slate-400 text-sm mb-2">{stat.label}</p>
            <p className="text-2xl font-bold text-white">{stat.value}</p>
            <p className="text-xs text-green-400 mt-2">{stat.change}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
